import { describe, it, expect } from 'vitest';
import { griffinLim } from '../src/griffin-lim';
import { stft, type STFTConfig } from '../src/audio-stft';

function magnitudeRMSE(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch: ${a.length} vs ${b.length}`);
  }
  let sumSq = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i] - b[i];
    sumSq += d * d;
  }
  return Math.sqrt(sumSq / a.length);
}

function meanAbs(a: Float32Array): number {
  let sum = 0;
  for (let i = 0; i < a.length; i++) sum += Math.abs(a[i]);
  return sum / a.length;
}

function makeSinusoid(freqHz: number, sampleRate: number, n: number): Float32Array {
  const out = new Float32Array(n);
  for (let i = 0; i < n; i++) {
    out[i] = Math.sin((2 * Math.PI * freqHz * i) / sampleRate);
  }
  return out;
}

describe('griffinLim', () => {
  const config: STFTConfig = { nFft: 512, hopLength: 128 };

  it('recovers a sinusoid from its magnitude', () => {
    const sampleRate = 16000;
    const n = 4096;
    const audio = makeSinusoid(1000, sampleRate, n);

    const target = stft(audio, config);
    // Drop phase — only magnitude is given.
    const recon = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 30,
    });

    const reconStft = stft(recon.audio, config);
    const rmse = magnitudeRMSE(reconStft.magnitude, target.magnitude);
    const meanTarget = meanAbs(target.magnitude);
    const relErr = rmse / meanTarget;
    expect(relErr).toBeLessThan(0.05);
  });

  it('returns a real Float32Array with finite values', () => {
    const audio = makeSinusoid(800, 16000, 4096);
    const target = stft(audio, config);
    const recon = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 10,
    });

    expect(recon.audio).toBeInstanceOf(Float32Array);
    for (let i = 0; i < recon.audio.length; i++) {
      expect(Number.isFinite(recon.audio[i])).toBe(true);
    }
  });

  it('more iterations do not hurt convergence', () => {
    const audio = makeSinusoid(1200, 16000, 4096);
    const target = stft(audio, config);

    const recon10 = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 10,
    });
    const recon50 = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 50,
    });

    const stft10 = stft(recon10.audio, config);
    const stft50 = stft(recon50.audio, config);

    const err10 = magnitudeRMSE(stft10.magnitude, target.magnitude);
    const err50 = magnitudeRMSE(stft50.magnitude, target.magnitude);

    // 50 iterations should be at least as good as 10 (with small slack for FP noise).
    expect(err50).toBeLessThanOrEqual(err10 * 1.01);
  });

  describe('validation', () => {
    it('throws when iterations < 1', () => {
      const audio = makeSinusoid(1000, 16000, 1024);
      const target = stft(audio, config);
      expect(() =>
        griffinLim({
          magnitude: target.magnitude,
          nFrames: target.nFrames,
          config,
          iterations: 0,
        }),
      ).toThrow(RangeError);
    });

    it('throws when magnitude.length does not match nFrames * nFreqs', () => {
      const audio = makeSinusoid(1000, 16000, 1024);
      const target = stft(audio, config);
      const wrongLen = new Float32Array(target.magnitude.length + 7);
      expect(() =>
        griffinLim({
          magnitude: wrongLen,
          nFrames: target.nFrames,
          config,
          iterations: 5,
        }),
      ).toThrow(RangeError);
    });
  });

  it('is deterministic with zero initial phase', () => {
    const audio = makeSinusoid(950, 16000, 4096);
    const target = stft(audio, config);

    const a = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 15,
      initialPhase: 'zero',
    });
    const b = griffinLim({
      magnitude: target.magnitude,
      nFrames: target.nFrames,
      config,
      iterations: 15,
      initialPhase: 'zero',
    });

    expect(a.audio.length).toBe(b.audio.length);
    for (let i = 0; i < a.audio.length; i++) {
      expect(a.audio[i]).toBe(b.audio[i]);
    }
  });
});
